148:     @Override
149:     public void initChannel(
150:             Route route,
151:             NamedNode definition,
152:             NamedNode childDefinition,
153:             List<InterceptStrategy> interceptors,
154:             Processor nextProcessor,
155:             NamedRoute routeDefinition,
156:             boolean first)
157:             throws Exception {
158:         this.route = route;
159:         this.nextProcessor = nextProcessor;
160: 
161:         // init CamelContextAware as early as possible on nextProcessor
162:         CamelContextAware.trySetCamelContext(nextProcessor, camelContext);
163: 
164:         // the definition to wrap should be the fine grained,
165:         // so if a child is set then use it, if not then its the original output used
166:         NamedNode targetOutputDef = childDefinition != null ? childDefinition : definition;
167:         LOG.trace("Initialize channel for target: {}", targetOutputDef);
168: 
169:         // setup instrumentation processor for management (jmx)
170:         // this is later used in postInitChannel as we need to setup the error handler later as well
171:         ManagementInterceptStrategy managed = route.getManagementInterceptStrategy();
172:         if (managed != null) {
173:             instrumentationProcessor = managed.createProcessor(targetOutputDef, nextProcessor);
174:         }
175: 
176:         // then wrap the output with the tracer and debugger (debugger first,
177:         // as we do not want regular tracer to trace the debugger)
178:         if (camelContext.isDebugStandby() || route.isDebugging()) {
179:             final Debugger customDebugger = camelContext.getDebugger();
180:             final MessageHistoryFactory messageHistoryFactory = camelContext.getMessageHistoryFactory();
181:             if (customDebugger != null) {
182:                 // use custom debugger
183:                 addAdvice(new MessageHistoryAdvice(messageHistoryFactory, targetOutputDef));
184:                 addAdvice(new DebuggerAdvice(customDebugger, nextProcessor, targetOutputDef));
185:             }
186:             BacklogDebugger debugger = getBacklogDebugger(camelContext, customDebugger == null);
187:             if (debugger != null) {
188:                 // use backlog debugger
189:                 if (!camelContext.hasService(debugger)) {
190:                     camelContext.addService(debugger);
191:                 }
192:                 // skip debugging inside rest-dsl (just a tiny facade) or kamelets / route-templates
193:                 boolean skip = routeDefinition != null
194:                         && (routeDefinition.isCreatedFromRest() || routeDefinition.isCreatedFromTemplate());
195:                 if (!skip && routeDefinition != null) {
196:                     backlogDebuggerSetupInitialBreakpoints(definition, routeDefinition, first, debugger, targetOutputDef);
197:                     if (first && debugger.isSingleStepIncludeStartEnd()) {
198:                         // debugger captures message history, and we need to capture history of incoming
199:                         addAdvice(
200:                                 new MessageHistoryAdvice(camelContext.getMessageHistoryFactory(), routeDefinition.getInput()));
