754:     /**
755:      * Creates a new instance of some kind of composite processor which defaults to using a {@link Pipeline} but derived
756:      * classes could change the behaviour
757:      */
758:     protected Processor createCompositeProcessor(List<Processor> list) throws Exception {
759:         return Pipeline.newInstance(camelContext, list);
760:     }
