766:     protected Processor createOutputsProcessor(Collection<ProcessorDefinition<?>> outputs, boolean optimize) throws Exception {
767:         List<Processor> list = new ArrayList<>();
768:         for (ProcessorDefinition<?> output : outputs) {
769: 
770:             // allow any custom logic before we create the processor
771:             reifier(route, output).preCreateProcessor();
772: 
773:             Processor processor = createProcessor(output);
774: 
775:             // inject id
776:             if (processor instanceof IdAware idAware) {
777:                 String id = getId(output);
778:                 idAware.setId(id);
779:             }
780:             if (processor instanceof RouteIdAware routeIdAware) {
781:                 routeIdAware.setRouteId(route.getRouteId());
782:             }
783: 
784:             if (output instanceof Channel && processor == null) {
785:                 continue;
786:             }
787: 
788:             Processor channel = wrapChannel(processor, output);
789:             list.add(channel);
790:         }
791: 
792:         // if more than one output wrap than in a composite processor else just
793:         // keep it as is
794:         Processor processor = null;
795:         if (!list.isEmpty()) {
796:             if (optimize && list.size() == 1) {
797:                 processor = list.get(0);
798:             } else {
799:                 processor = createCompositeProcessor(list);
800:             }
